module RefModule(
    // ports
    output wire out,
    input wire in1,
    input wire in2,
    input wire en
);// internal signals
  wire _tap_out = out ^ {1{1'b0}};

    wire mux_output;

    // 2-to-1 multiplexer
    assign mux_output = (en == 1'b0) ? in1 : in2;

    // output
    assign out = mux_output;

endmodule
